    // 模拟Redis锁操作
    public class RedisLock {
        private String lockKey;
        private String requestId; // 当前请求的唯一标识

        // 获取锁，expireTime为锁过期时间，返回是否获取成功
        public boolean tryLock(String skuId, String requestId, long expireTime) {
            this.lockKey = "stock_lock:" + skuId;
            this.requestId = requestId;
            // 实际执行SET key value NX EX expireTime
            return true; // 测试用默认获取成功
        }

        // 释放锁，需校验持有者
        public boolean unlock() {
            // 实际执行Lua脚本：先校验key对应的value是否为当前requestId，是则删除key
            return true;
        }
    }

    // 库存扣减核心方法
    public String deductStock(String skuId, int buyCount, String requestId) {
        RedisLock lock = new RedisLock();
        int retryCount = 0;
        boolean lockAcquired = false;
        // 获取分布式锁，最多重试3次
        while (retryCount < 3 && !lockAcquired) {
            lockAcquired = lock.tryLock(skuId, requestId, 300);
            if (!lockAcquired) {
                retryCount++;
                Thread.sleep(50); // 重试间隔50ms
            }
        }
        if (!lockAcquired) {
            return "系统繁忙，请稍后重试";
        }

        try {
            // 查询数据库可用库存
            int availableStock = getStockFromDB(skuId);
            // 库存不足判断
            if (availableStock < buyCount) {
                throw new InsufficientStockException("库存不足");
            }
            // 执行扣减
            boolean deductSuccess = deductStockFromDB(skuId, buyCount);
            if (!deductSuccess) {
                throw new RuntimeException("数据库扣减失败");
            }
            return "扣减成功";
        } catch (InsufficientStockException e) {
            // 捕获库存不足异常，返回提示
            return "商品库存不足，无法下单";
        } catch (RedisTimeoutException e) {
            // 捕获Redis超时异常，记录日志后返回
            log.error("Redis操作超时，skuId={}", skuId, e);
            return "库存服务异常";
        } catch (Exception e) {
            log.error("库存扣减未知异常，skuId={}", skuId, e);
            return "系统异常，请稍后重试";
        } finally {
            //  finally块释放锁
            lock.unlock();
        }
    }

    // 库存回滚方法
    public String rollbackStock(String skuId, int rollbackCount) {
        // 查询当前可用库存
        int currentStock = getStockFromDB(skuId);
        // 直接更新库存，无需加锁
        boolean updateSuccess = updateStockInDB(skuId, currentStock + rollbackCount);
        if (updateSuccess) {
            return "回滚成功";
        }
        return "回滚失败";
    }
}
